import { Platform } from 'react-native';

const API_BASE_URL = 'https://api.example.com';
const LOCAL_DEVICE_BASE_URL = 'http://192.168.x.x';

const createHeaders = (token = null, contentType = 'application/json') => {
  const headers = {
    'Content-Type': contentType,
    'Accept': 'application/json',
  };

  if (token) {
    headers['Authorization'] = `Bearer ${token}`;
  }

  return headers;
};

const handleResponse = async (response) => {
  if (!response.ok) {
    const errorData = await response.json().catch(() => ({}));
    throw new Error(errorData.message || `HTTP error! status: ${response.status}`);
  }
  
  const contentType = response.headers.get('content-type');
  if (contentType && contentType.includes('application/json')) {
    return response.json();
  }
  
  return response.text();
};

const apiClient = {
  get: async (endpoint, token = null) => {
    try {
      const url = `${API_BASE_URL}${endpoint}`;
      const response = await fetch(url, {
        method: 'GET',
        headers: createHeaders(token),
        timeout: 10000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`GET request failed: ${error.message}`);
    }
  },

  post: async (endpoint, data, token = null, contentType = 'application/json') => {
    try {
      const url = `${API_BASE_URL}${endpoint}`;
      const response = await fetch(url, {
        method: 'POST',
        headers: createHeaders(token, contentType),
        body: contentType === 'application/json' ? JSON.stringify(data) : data,
        timeout: 10000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`POST request failed: ${error.message}`);
    }
  },

  put: async (endpoint, data, token = null) => {
    try {
      const url = `${API_BASE_URL}${endpoint}`;
      const response = await fetch(url, {
        method: 'PUT',
        headers: createHeaders(token),
        body: JSON.stringify(data),
        timeout: 10000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`PUT request failed: ${error.message}`);
    }
  },

  delete: async (endpoint, token = null) => {
    try {
      const url = `${API_BASE_URL}${endpoint}`;
      const response = await fetch(url, {
        method: 'DELETE',
        headers: createHeaders(token),
        timeout: 10000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`DELETE request failed: ${error.message}`);
    }
  },
};

const localDeviceClient = {
  get: async (endpoint, port = 80) => {
    try {
      const url = `http://${LOCAL_DEVICE_BASE_URL}:${port}${endpoint}`;
      const response = await fetch(url, {
        method: 'GET',
        timeout: 5000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`Local device GET request failed: ${error.message}`);
    }
  },

  post: async (endpoint, data, port = 80) => {
    try {
      const url = `http://${LOCAL_DEVICE_BASE_URL}:${port}${endpoint}`;
      const response = await fetch(url, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(data),
        timeout: 5000,
      });
      
      return await handleResponse(response);
    } catch (error) {
      throw new Error(`Local device POST request failed: ${error.message}`);
    }
  },
};

